const body = $input.first().json.body || $input.first().json;

const lead = {
  name:        (body.name      || '').trim(),
  email:       (body.email     || '').trim().toLowerCase(),
  phone:       (body.phone     || '').trim(),
  company:     (body.company   || '').trim(),
  role:        (body.role      || '').trim(),
  website:     (body.website   || '').trim(),
  employees:   (body.employees || '').trim(),
  budget:      (body.budget    || '').trim(),
  message:     (body.message   || '').trim(),
  source:      body.source     || 'webhook',
  captured_at: new Date().toISOString()
};

if (!lead.email || !lead.name) {
  throw new Error('Missing required fields: name and email are mandatory.');
}

return [{ json: lead }];

const lead = $('Normalize Lead Data').first().json;
const response = $input.first().json;

let rawText = '';
try {
  rawText = response.candidates[0].content.parts[0].text || '{}';
  rawText = rawText.replace(/```json|```/g, '').trim();
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) rawText = jsonMatch[0];
} catch(e) {
  rawText = '{}';
}

let qualification;
try {
  qualification = JSON.parse(rawText);
} catch(e) {
  qualification = {
    score: 7,
    tier: 'Warm',
    reasoning: 'Fallback qualification',
    recommended_action: 'Send nurture email',
    icp_match: true
  };
}

const usage = response.usageMetadata || {};
const tokenLog = {
  prompt_tokens: usage.promptTokenCount || 0,
  completion_tokens: usage.candidatesTokenCount || 0,
  total_tokens: usage.totalTokenCount || 0,
  estimated_cost_usd: '0.000000'
};

return [{ json: { 
  ...lead, 
  qualification, 
  token_usage: tokenLog, 
  qualified_at: new Date().toISOString() 
}}];

