const lead = $('Parse & Merge Qualification').first().json;
const response = $input.first().json;

let emailBody = '';

try {
  emailBody = response.candidates[0].content.parts[0].text.trim();

  // Clean excessive new lines
  emailBody = emailBody.replace(/\n{3,}/g, '\n\n');

} catch(e) {
  emailBody = 'Something went wrong generating the email.';
}

const usage = response.usageMetadata || {};
const prev = lead.token_usage || {};

const combined = {
  prompt_tokens: (prev.prompt_tokens || 0) + (usage.promptTokenCount || 0),
  completion_tokens: (prev.completion_tokens || 0) + (usage.candidatesTokenCount || 0),
  total_tokens: (prev.total_tokens || 0) + (usage.totalTokenCount || 0),
  estimated_cost_usd: '0.000000'
};

const fullEmail =
`
${emailBody}
`;

return [{ json: { ...lead, email_body: fullEmail, token_usage: combined } }];

const lead = $('Merge Email Draft').first().json;

console.log('=== LEAD PROCESSED ===');
console.log(`Name:    ${lead.name}`);
console.log(`Email:   ${lead.email}`);
console.log(`Company: ${lead.company}`);
console.log(`Tier:    ${lead.qualification.tier} (Score: ${lead.qualification.score}/10)`);
console.log(`Action:  ${lead.qualification.recommended_action}`);
console.log(`Tokens:  ${lead.token_usage.total_tokens} (~$${lead.token_usage.estimated_cost_usd})`);
console.log('======================');

return [{
  json: {
    status:             'success',
    lead_email:         lead.email,
    tier:               lead.qualification.tier,
    score:              lead.qualification.score,
    action_taken:       lead.qualification.recommended_action,
    email_sent_to:      lead.email,
    crm_updated:        true,
    supabase_updated:   true,
    total_tokens_used:  lead.token_usage.total_tokens,
    estimated_cost_usd: lead.token_usage.estimated_cost_usd,
    processed_at:       new Date().toISOString()
  }
}];

